diff --git a/tests/shared_boundaries.test.ts b/tests/shared_boundaries.test.ts
new file mode 100644
index 0000000..fd49268
--- /dev/null
+++ b/tests/shared_boundaries.test.ts
@@ -0,0 +1,109 @@
+// Boundary / edge-case correctness for the shared standup utilities.
+//
+// These assert behaviour on inputs the package's own unit tests never feed:
+// an afternoon (and midnight) instant rendered as a schedule time key, the
+// day-after key resolved against a fixed clock, the Instagram check-in
+// callback action, a blank integration-item title, and a fractional workflow
+// index. The existing suites only exercise morning/explicit values and the
+// index guards they already pin, so a regression on these edges stays green
+// there while being wrong here.
+
+import { afterEach, describe, expect, it, setSystemTime } from "bun:test";
+
+import { parseCallback } from "../packages/shared/src/callbacks";
+import { toDateKey, tomorrowDateKey } from "../packages/shared/src/dates";
+import {
+  integrationItemSchema,
+  standupStateSchema,
+} from "../packages/shared/src/schemas";
+import { toTimeKey } from "../packages/shared/src/time";
+
+const baseState = {
+  blockers: [],
+  completedHabitIds: [],
+  habitIndex: 0,
+  habits: [],
+  step: "wake_check",
+  taskIndex: 0,
+  taskReviews: [],
+  tasks: [],
+};
+
+afterEach(() => {
+  setSystemTime();
+});
+
+describe("time key formatting", () => {
+  it("renders afternoon and midnight instants in 24-hour form", () => {
+    expect(toTimeKey(new Date("2026-01-01T13:30:00Z"), "UTC")).toBe("13:30");
+    expect(toTimeKey(new Date("2026-01-01T00:15:00Z"), "UTC")).toBe("00:15");
+    expect(toTimeKey(new Date("2026-01-01T23:59:00Z"), "UTC")).toBe("23:59");
+  });
+
+  it("leaves morning and noon instants unchanged", () => {
+    expect(toTimeKey(new Date("2026-01-01T09:05:00Z"), "UTC")).toBe("09:05");
+    expect(toTimeKey(new Date("2026-01-01T12:00:00Z"), "UTC")).toBe("12:00");
+  });
+});
+
+describe("tomorrow date key", () => {
+  it("advances to the next calendar day", () => {
+    setSystemTime(new Date("2026-03-15T12:00:00Z"));
+    expect(tomorrowDateKey("UTC")).toBe("2026-03-16");
+    setSystemTime(new Date("2026-12-31T18:00:00Z"));
+    expect(tomorrowDateKey("UTC")).toBe("2027-01-01");
+  });
+
+  it("keeps the same-day key in agreement with the wall clock", () => {
+    setSystemTime(new Date("2026-06-10T08:00:00Z"));
+    expect(toDateKey(new Date(), "UTC")).toBe("2026-06-10");
+  });
+});
+
+describe("callback action gate", () => {
+  it("accepts the instagram check-in action", () => {
+    expect(parseCallback("standup:instagram:done")).toEqual({
+      namespace: "standup",
+      action: "instagram",
+      value: "done",
+    });
+  });
+
+  it("still rejects an unknown action", () => {
+    expect(parseCallback("standup:nope:done")).toBeNull();
+  });
+});
+
+describe("integration item title", () => {
+  it("rejects a blank title", () => {
+    expect(
+      integrationItemSchema.safeParse({ id: "task-1", title: "" }).success,
+    ).toBeFalse();
+  });
+
+  it("accepts a normal titled item", () => {
+    expect(
+      integrationItemSchema.safeParse({ id: "task-1", title: "Read" }).success,
+    ).toBeTrue();
+  });
+});
+
+describe("standup state indices", () => {
+  it("rejects a fractional habit index", () => {
+    expect(
+      standupStateSchema.safeParse({ ...baseState, habitIndex: 2.5 }).success,
+    ).toBeFalse();
+  });
+
+  it("still rejects a negative habit index", () => {
+    expect(
+      standupStateSchema.safeParse({ ...baseState, habitIndex: -1 }).success,
+    ).toBeFalse();
+  });
+
+  it("accepts a zero habit index", () => {
+    expect(
+      standupStateSchema.safeParse({ ...baseState, habitIndex: 0 }).success,
+    ).toBeTrue();
+  });
+});
